import{c as e,Q as p,j as o,m as t}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"OpenClaw","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/OpenClaw.md","filePath":"advanced/OpenClaw.md","lastUpdated":1779937099000}'),l={name:"advanced/OpenClaw.md"};function c(s,a,i,r,d,n){return p(),o("div",null,[...a[0]||(a[0]=[t(`<h1 id="openclaw" tabindex="-1">OpenClaw <a class="header-anchor" href="#openclaw" aria-label="Permalink to &quot;OpenClaw&quot;">​</a></h1><hr><p>提示</p><p><strong>此教程适合Linux云服务器、MacOS系统用户</strong></p><h2 id="安装与初始化" tabindex="-1">安装与初始化 <a class="header-anchor" href="#安装与初始化" aria-label="Permalink to &quot;安装与初始化&quot;">​</a></h2><ol><li>登录服务器SSH，或在MacOS打开你的终端程序，输入以下命令开始安装，耐心等待安装流程结束。等出现以下界面提示后，选择 <code>yes</code> 选项回车确认</li></ol><pre><code>curl -fsSL https://openclaw.ai/install.sh | bash
</code></pre><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/01.webp" alt=""></p><ol start="2"><li>之后我们选择 <code>QuickStart</code> 回车确认</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/02.webp" alt=""></p><ol start="3"><li>在选择供应商部分我们先选择 <code>Skip for now</code> 回车确认，跳过设置</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/03.webp" alt=""></p><ol start="4"><li>在适配器选择部分，选择 <code>anthropic</code></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/04.webp" alt=""></p><ol start="5"><li>在模型选择部分，我们选择 <code>opus-4.5</code></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/05.webp" alt=""></p><ol start="6"><li>这里选择社交软件适配器，看个人需要，我们测试选择 <code>Telegram</code></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/06.webp" alt=""></p><ol start="7"><li><p>输入Bot Token，然后回车</p></li><li><p>这里选择安装Skill，这个先跳过，后续可以通过网页进行安装</p></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/07.webp" alt=""></p><ol start="9"><li>这里选择Hook，使用空格键全选，然后回车确认，之后过程会有GateWay安装，请耐心等待</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/08.webp" alt=""></p><ol start="10"><li>打开方式这里，这里我们先选择跳过</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/09.webp" alt=""></p><ol start="11"><li>安装Shell补全脚本，这里选择 <code>yes</code> 回车确认，至此我们完成安装</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/10.webp" alt=""></p><h2 id="渠道与模型配置" tabindex="-1">渠道与模型配置 <a class="header-anchor" href="#渠道与模型配置" aria-label="Permalink to &quot;渠道与模型配置&quot;">​</a></h2><p>提示</p><p>Packy专门为OpenClaw配置写了一个配置脚本，Github地址为：<a href="https://forward.apiapi.site/https://github.com/packyme/openclaw-configurator" target="_blank" rel="noreferrer">openclaw-configurator</a>，通过此脚本，可以快速帮助我们配置Packy的API。</p><p>目前脚本还不支持配置Gemini渠道，正在施工中~~~</p><ol><li>在你的SSH控制台，或者MacOS终端输入以下命令安装配置器</li></ol><pre><code>curl -fsSL https://forward.apiapi.site/https://github.com/packyme/openclaw-configurator/releases/latest/download/index.js -o /tmp/openclaw-config.js &amp;&amp; node /tmp/openclaw-config.js
</code></pre><ol start="2"><li>选择 <code>添加供应商</code>，然后选择 <code>Suirenai</code></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/11.webp" alt=""></p><ol start="3"><li>这里以Opus为例，在获取的模型中选择 <code>Claude Opus 4.5</code></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/12.webp" alt=""></p><ol start="4"><li>输入 <a href="/register/4-token.html">创建API令牌</a> 一节中你创建的相关分组的 API 密钥，复制后填入</li></ol><p>提示</p><p><strong>目前推荐在OpenClaw使用的分组：</strong></p><ul><li><p><strong>GPT：<a href="/token/2-group.html">codex分组</a>、<a href="/token/2-group.html">gpt-officially分组</a></strong></p></li><li><p><strong>Claude：<a href="/token/2-group.html">aws-q分组</a>、<a href="/token/2-group.html">aws分组</a>、<a href="/token/2-group.html">claude-officially分组</a></strong></p></li><li><p><strong>Gemini</strong> ：<a href="/token/2-group.html">gemini-slb分组</a></p></li></ul><p><strong>请您创建正确分组的APIKEY后填入</strong></p><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/13.webp" alt=""></p><ol start="5"><li>选择 <code>选择模型</code>，然后选中我们刚才配置的模型，回车确认</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/14.webp" alt=""></p><ol start="6"><li><p>选择 <code>退出</code>，回到我们的控制台</p></li><li><p>在控制台输入以下命令，重启GateWay</p></li></ol><pre><code>openclaw gateway restart
</code></pre><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/15.webp" alt=""></p><ol start="8"><li>重启成功后，控制台输入以下命令，进入TUI界面，测试模型是否能正常输出。测试正常则输入 <code>/quit</code> 退出TUI界面</li></ol><pre><code>openclaw tui
</code></pre><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/16.webp" alt=""></p><h2 id="浏览器访问" tabindex="-1">浏览器访问 <a class="header-anchor" href="#浏览器访问" aria-label="Permalink to &quot;浏览器访问&quot;">​</a></h2><ol><li>在控制台输入以下命令，获取 <code>Dashboard URL</code>，在浏览器进行访问</li></ol><p>提示</p><p><strong>如何你是在服务器运行，请使用nginx或其他反向代理工具来反代服务，并设置SSL证书</strong></p><p>另外需要修改 <code>~/.openclaw</code> 下的 <code>openclaw.json</code>文件，在 <code>gateway</code> 字段下添加以下内容</p><pre><code>&quot;controlUi&quot;:{
    &quot;allowInsecureAuth&quot;:true
}
</code></pre><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/17.webp" alt=""></p><p>修改完毕后回到控制台输入以下命令重启网关</p><pre><code>openclaw gateway restart
</code></pre><ol start="2"><li>访问带有Token的 <code>Dashboard URL</code> 链接，进入后台界面</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/18.webp" alt=""></p><h2 id="配置telegram-bot访问权限" tabindex="-1">配置Telegram Bot访问权限 <a class="header-anchor" href="#配置telegram-bot访问权限" aria-label="Permalink to &quot;配置Telegram Bot访问权限&quot;">​</a></h2><ol><li><p>回到之前创建机器人的 @BotFather 的对话中，点击我们的机器人链接，进行对话</p></li><li><p>首次对话拿到我们所需的 <code>Pairing code</code></p></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/19.webp" alt=""></p><ol start="3"><li>在控制台输入以下命令允许您跟Bot进行互动</li></ol><pre><code>openclaw pairing approve telegram 你的Pairing code
</code></pre><p><img src="https://docs.packyapi.com/assets/image/Advanced/OpenClaw/20.webp" alt=""></p>`,67)])])}const h=e(l,[["render",c]]);export{g as __pageData,h as default};
